-- 2026 World Cup real schedule sync
-- Generated from backend/worldcup2026-schedule.js. Times are Beijing time (+08).
-- Run this in Supabase SQL Editor after deploying the code.

BEGIN;

DELETE FROM votes;
DELETE FROM vote_stats;
UPDATE users SET total_votes = 0, correct_votes = 0;
UPDATE bottles SET match_id = NULL;
DELETE FROM matches;
ALTER SEQUENCE IF EXISTS matches_id_seq RESTART WITH 1;


SELECT id FROM matches
ON CONFLICT (match_id) DO NOTHING;

COMMIT;

SELECT COUNT(*) AS match_count, MIN(match_time) AS first_match, MAX(match_time) AS last_match FROM matches;
SELECT id, group_name, round, home_team, away_team, match_time, status FROM matches ORDER BY match_time ASC LIMIT 5;
